script:
frappe.ui.form.on("Sample Collection", {
    refresh: function(frm) {

        if (frm.doc.name) {

            let canvas = document.createElement("canvas");
            JsBarcode(canvas, frm.doc.name, {
                format: "CODE128",
                width: 2,
                height: 60,
                displayValue: false
            });

            let base64 = canvas.toDataURL("image/png").split(",")[1];

            frm.set_value("custom_barcode_html", base64);
        }
    }
});
